54bd6a32-46d7-48bf-88bb-e7caf8680263	8589c927-3407-4699-a382-d6df6a045d8b	29	<chunk_context>Tư vấn dịch vụ cấp nước đa tầng tại Dr. Medispa, ưu đãi cho khách hàng mới.</chunk_context>\n\nKhông biết chị cần em tư vấn hoặc giải đáp thêm gì về dịch vụ cấp nước đa tầng không ạ? Hiện tại bên em đang có nhiều quà tặng đặc biệt cho khách hàng mới, em mời chị sắp xếp thời gian qua spa chăm sóc và thư giãn nhé ạ!",	< chunk_context > Tư_vấn dịch_vụ cấp_nước đa_tầng tại Dr._Medispa , ưu_đãi cho khách_hàng mới . < / chunk_context > Không biết chị cần em tư_vấn hoặc giải_đáp thêm gì về dịch_vụ cấp_nước đa_tầng không ạ ? Hiện_tại bên em đang có nhiều quà tặng đặc_biệt cho khách_hàng mới , em mời chị sắp_xếp thời_gian qua spa chăm_sóc và thư_giãn nhé ạ ! " ,	b4b08b31c173815fc68780dce5f0ecfd02f9c6877c66206acdd272cf80d2b6f2	[0.0431408,0.05385287,0.11089724,0.02815163,0.07466318,-0.0398728,-0.01180944,0.07809924,0.07860661,-0.0365799,-0.02882855,0.04371223,0.10556348,-0.03671698,-0.04011443,-0.07650383,-0.01478001,0.03279092,0.04732871,0.07966293,-0.15426077,-0.0058475,-0.07361832,-0.04291146,-0.02755518,-0.07208012,0.02595664,0.06020186,-0.05445549,-0.0356726,0.05291273,-0.04159854,-0.03271572,0.07828504,0.103919,-0.07346264,0.01269429,-0.04393405,-0.00486684,-0.00760645,-0.08574962,0.03878072,0.04345974,0.04447787,0.04940552,0.03053812,-0.04023147,-0.02616717,0.09763679,0.03363607,-0.04038732,-0.0092642,0.02703382,0.00537765,-0.04206095,0.02742909,-0.03578964,0.01112402,0.06962903,-0.00045738,-0.00423604,0.06018256,0.00449673,0.01845957,-0.01685307,0.04786341,-0.05703096,0.01847953,0.03369288,-0.0331918,0.07443663,0.06346402,-0.01134014,0.07763904,0.03830808,-0.01234646,0.01322786,0.04206296,-0.10158038,-0.07605127,-0.05918123,0.06564426,-0.00442243,-0.04328354,-0.00563629,-0.07280165,0.06438161,-0.00626023,0.12328175,0.01016989,-0.00045291,-0.01645898,-0.02869144,0.00349018,0.05283393,0.04361523,-0.12063033,0.04396512,0.02950461,0.0380738,0.06599709,0.01761352,-0.07577273,0.024033