de344d2d-1cd1-4ca2-a53f-b7938fe3e081	8589c927-3407-4699-a382-d6df6a045d8b	54	<chunk_context>Tư vấn dịch vụ trẻ hóa da Ultherapy tại Dr. Medispa, khuyến mãi khách hàng mới</chunk_context>\n\nKhông biết chị cần em tư vấn hoặc giải đáp thêm gì về dịch vụ trẻ hóa da Ultherapy không ạ? Hiện tại bên em đang có nhiều quà tặng đặc biệt cho khách hàng mới, em mời chị sắp xếp thời gian qua spa chăm sóc và thư giãn nhé ạ!",	< chunk_context > Tư_vấn dịch_vụ trẻ hóa da Ultherapy tại Dr._Medispa , khuyến_mãi khách_hàng mới < / chunk_context > Không biết chị cần em tư_vấn hoặc giải_đáp thêm gì về dịch_vụ trẻ hóa da_Ultherapy không ạ ? Hiện_tại bên em đang có nhiều quà tặng đặc_biệt cho khách_hàng mới , em mời chị sắp_xếp thời_gian qua spa chăm_sóc và thư_giãn nhé ạ ! " ,	b7d717feeb1275551d9012979c90d83fe12d73fc4e62b67f0762656aa50acc8e	[0.04858097,0.04671994,0.1063786,0.05107937,0.05935832,-0.045096,0.00262954,0.08210975,0.09315582,-0.02581768,0.02290038,0.06006164,0.07349719,-0.02542732,-0.00979847,-0.03486032,0.00119158,0.03342525,0.07009792,0.07955569,-0.15344827,-0.00912331,-0.06532993,-0.02733728,-0.02437786,-0.07024097,0.05514456,-0.02176968,-0.06881545,-0.02046518,0.01051571,-0.06199131,-0.03957001,0.06625549,0.06439257,-0.02509084,-0.03122601,-0.0034768,0.01679921,-0.01241728,-0.08061352,-0.00231228,0.03634597,0.06443418,0.00815448,0.02145343,-0.05673751,0.02420569,0.097531,0.02156794,-0.04964953,0.00984809,0.00079583,0.00673371,0.01597361,0.04497493,0.00076526,-0.0129928,0.05926183,0.03175024,-0.00156452,0.02081351,0.00865169,0.03456604,0.01121121,0.03495285,-0.04897652,0.07066894,0.00174952,-0.05553682,0.07189675,0.07543126,0.00323267,0.06253058,0.04190399,0.00724271,0.03183593,0.02052534,-0.08260614,-0.05997131,-0.05474987,0.05503115,-0.03864517,-0.00813466,0.01141138,-0.0489471,0.06995592,0.03572888,0.11275368,-0.01033063,-0.02937526,-0.04892591,-0.00521994,-0.00896379,0.09409837,0.06630716,-0.10428908,0.0577095,0.01463109,0.00342159,0.04777569,0.07797109,-0.07646199,0.