5c08a884-e1df-4ad1-9e43-501af0f119b8	8589c927-3407-4699-a382-d6df6a045d8b	74	<chunk_context>Lời mời tư vấn và mời khách trải nghiệm dịch vụ tại Dr. Medispa với quà tặng đặc biệt dành cho khách mới, dùng chung cho các dịch vụ spa.</chunk_context>\n\nKhông biết chị cần em tư vấn hoặc giải đáp thêm gì về dịch vụ [thay tên dịch vụ] không ạ? Hiện tại bên em đang có nhiều quà tặng đặc biệt cho khách hàng mới, em mời chị sắp xếp thời gian qua spa chăm sóc và thư giãn nhé ạ!",	< chunk_context > Lời mời tư_vấn và mời khách trải_nghiệm dịch_vụ tại Dr._Medispa với quà tặng đặc_biệt dành cho khách mới , dùng chung cho các dịch_vụ spa . < / chunk_context > Không biết chị cần em tư_vấn hoặc giải_đáp thêm gì về dịch_vụ [ thay tên dịch_vụ ] không ạ ? Hiện_tại bên em đang có nhiều quà tặng đặc_biệt cho khách_hàng mới , em mời chị sắp_xếp thời_gian qua spa chăm_sóc và thư_giãn nhé ạ ! " ,	1cda3eab110ce3de78fdf0044f789a778a24fca6966ae29fc18a2da3d807a119	[0.01535533,0.03558285,0.12786262,0.05487039,0.08487443,-0.0378676,0.02828701,0.09391081,0.10554679,-0.03779234,-0.01181301,0.07245824,0.10823015,-0.01114765,-0.05143241,-0.04547163,-0.01590627,0.02069706,0.05241515,0.0809207,-0.15251856,-0.02030092,-0.073804,-0.02459073,-0.01037351,-0.09895373,0.05392287,0.01448637,-0.05374577,-0.02972421,0.01212788,-0.08058614,-0.05509973,0.07186849,0.1047333,-0.0599191,-0.02506807,-0.02362961,0.02359649,-0.01199735,-0.09983679,0.03791524,0.06141772,0.04576447,0.00476768,0.02986142,-0.02583325,-0.00326433,0.10373893,-0.00404901,-0.05215879,0.02990715,0.02443805,0.00064102,-0.00953795,0.05476565,-0.02024497,0.01024706,0.07296928,-0.03128635,-0.02167237,0.02187108,0.02207498,0.02037991,0.00902511,0.01698394,-0.04523066,0.0423422,0.02314819,-0.03587158,0.05437175,0.04808148,0.00403347,0.11059463,0.01853498,-0.00790371,0.00116692,0.05813332,-0.09036321,-0.05610169,-0.06670845,0.04975148,0.0096041,-0.03390395,-0.00115491,-0.05897429,0.06255584,0.0216181,0.10828176,-0.00489041,-0.00810728,-0.04143392,-0.03