bca7908d-1539-4c04-8970-395d61dd3ac7	8589c927-3407-4699-a382-d6df6a045d8b	102	<chunk_context>Tư vấn dịch vụ chăm sóc da chuyên sâu và mời khách đặt lịch tại Dr. Medispa</chunk_context>\n\nKhông biết chị cần em tư vấn hoặc giải đáp thêm gì về dịch vụ chăm sóc da chuyên sâu không ạ? Hiện tại bên em đang có nhiều quà tặng đặc biệt cho khách hàng mới, em mời chị sắp xếp thời gian qua spa chăm sóc và thư giãn nhé ạ!",\r\nBước 4: Chốt lịch,,,	< chunk_context > Tư_vấn dịch_vụ chăm_sóc da chuyên_sâu và mời khách đặt lịch tại Dr. Medispa < / chunk_context > Không biết chị cần em tư_vấn hoặc giải_đáp thêm gì về dịch_vụ chăm_sóc da chuyên_sâu không ạ ? Hiện_tại bên em đang có nhiều quà tặng đặc_biệt cho khách_hàng mới , em mời chị sắp_xếp thời_gian qua spa chăm_sóc và thư_giãn nhé ạ ! " , Bước 4 : Chốt lịch , , ,	dc18168caaf26397bfa3bee4ede15972dbf46f7bc9faefbcf0c70a2be978efae	[0.06028599,0.03190603,0.15841477,0.04925584,0.08287493,-0.03800149,-0.00605214,0.07187601,0.10723421,-0.03357204,-0.02898226,0.08370615,0.07220812,-0.00106996,-0.02256339,-0.01120333,0.01704826,0.05634526,0.08170888,0.09122407,-0.16034414,-0.02815275,-0.10539578,-0.06420334,-0.03993511,-0.07711738,0.02682268,0.02279958,-0.0625762,-0.04870825,0.01211131,-0.08734484,-0.01528816,0.07892695,0.06691787,-0.05125465,0.04221166,-0.02705036,0.01640365,-0.01850535,-0.06825905,0.04344963,0.07526514,0.06141608,-0.00728406,0.07152008,-0.07293979,-0.05305718,0.08925325,-0.01684388,-0.07833426,0.0488727,0.01650816,-0.016609,0.00255164,0.07234656,0.00809324,-0.00326001,0.05046172,-0.02296054,-0.02865726,0.03570139,0.01312237,0.03690004,0.01024533,0.0404029,-0.03094091,0.03441788,0.03500611,-0.04213374,0.0801186,0.06174827,0.00299006,0.1222061,0.01990202,-0.02058811,-0.03407744,0.04074356,-0.09373611,-0.00894049,-0.04586329,0.08302175,0.01301951,0.00800503,0.00767372,-0.06644531,0.02915934,0.05215816,0.10611376,0.00153795,0.00475359,-0.01277608,-0.02004223,-0.03067786,0.10361616,0.03631684,-0.08708535,0.06358321,0.00574