de80bf73-773f-47d7-976d-636bcbce809b	8589c927-3407-4699-a382-d6df6a045d8b	130	<chunk_context>Chính sách và quy trình triệt lông tại Dr. Medispa đảm bảo an toàn, chuẩn y khoa với dụng cụ dùng một lần cho mỗi khách hàng</chunk_context>\n\n. Quy trình triệt lông bên em chuẩn y khoa, với dụng cụ và đồ dùng dùng 1 lần cho mỗi lượt khách, đảm bảo an toàn cho khách hàng ạ.",	< chunk_context > Chính_sách và quy_trình triệt_lông tại Dr._Medispa đảm_bảo an_toàn , chuẩn y_khoa với dụng_cụ dùng một lần cho mỗi khách_hàng < / chunk_context > . Quy_trình triệt_lông bên em chuẩn y_khoa , với dụng_cụ và đồ_dùng dùng 1 lần cho mỗi lượt khách , đảm_bảo an_toàn cho khách_hàng ạ . " ,	2150e9496c6f290904959f64e3aabbe933c1470508b0007329cee0df256fbd85	[0.01528795,0.043597,0.07421484,0.03655605,0.0480808,-0.02397054,0.01519421,0.13334206,0.06660805,0.00226376,-0.01945195,0.11617424,0.06895524,0.0227346,0.01344352,0.01372643,-0.00801314,0.00491135,0.05692816,0.09230395,-0.13410118,-0.01963557,-0.05145705,-0.03351002,-0.03450168,-0.11205705,0.02450987,-0.0304866,-0.13295703,0.01536671,-0.03472007,-0.04070184,-0.02378833,0.0764834,0.06985466,-0.05032287,0.03798974,-0.00528001,0.00171489,-0.01523012,-0.04658838,0.05982947,0.0629589,0.0216456,0.01588733,-0.0395404,-0.02141676,0.0013093,0.05738043,0.00237088,-0.0067488,0.02122508,-0.00638797,-0.03231454,-0.03779436,0.06679619,-0.06245512,-0.02823561,0.07918353,0.01929108,-0.04221965,0.03459252,0.0006389,0.01685953,0.01516009,-0.01879197,-0.02945188,0.05369055,0.03642127,-0.01514768,0.0741944,0.06040393,0.01989279,0.13169545,0.01068805,0.03372003,0.05888563,0.03199039,-0.06083192,-0.00181433,-0.03905438,0.04351158,-0.00756037,-0.04043009,0.04445253,-0.02770839,0.04848716,0.1019716,0.07563428,-0.00922075,-0.00928684,-0.04495901,-0.06235791,0.02542271,0.08361518,0.04413795,-0.13153979,0.05794621,0.0508206,0.02271955,0.01719776,0.03880132,-0.04257013,0.03661058,0.071422,0.04619921,0.0254099,-0.05454747,-0.01036099,0.01103565,0.05343106,0.07244826,-0