00536385-763d-415e-9d15-18319f6f7b0b	8589c927-3407-4699-a382-d6df6a045d8b	190	<chunk_context>Ưu đãi dịch vụ gội đầu dưỡng sinh cho khách hàng mới tại Dr. Medispa (giá 99K/buổi, thời gian 60 phút)</chunk_context>\n\nHiện tại, bên em đang có chương trình ưu đãi đặc biệt cho khách hàng mới trải nghiệm dịch vụ với giá chỉ 99K/buổi (giá gốc: 350k/buổi) trong vòng 60 phút. Sau 1 buổi chị sẽ cảm thấy cơ thể khỏe khoắn, đỡ mỏi mệt hơn hẳn ạ.	< chunk_context > Ưu_đãi dịch_vụ gội đầu dưỡng_sinh cho khách_hàng mới tại Dr._Medispa ( giá 99K / buổi , thời_gian 60 phút ) < / chunk_context > Hiện_tại , bên em đang có chương_trình ưu_đãi đặc_biệt cho khách_hàng mới trải_nghiệm dịch_vụ với giá chỉ 99K / buổi ( giá gốc : 350 k / buổi ) trong vòng 60 phút . Sau 1 buổi chị sẽ cảm_thấy cơ_thể khỏe khoắn , đỡ mỏi_mệt hơn hẳn ạ .	b147f3b18b264c4e0eb29edca1c2cf88b24ef4a94813df43df35f0e1f2a50fc3	[0.01319973,0.03800143,0.09881768,0.0180986,0.05017526,-0.05027569,-0.00930969,0.12249158,0.08667257,-0.04157232,-0.0116711,0.07170229,0.08030262,0.01190939,-0.0588005,-0.02486825,0.01372332,0.0009121,0.05880699,0.08353246,-0.1700307,-0.00865723,-0.04404113,-0.02648765,-0.01063054,-0.13717219,0.03732553,0.01593195,-0.07229859,-0.01538164,-0.00586261,-0.06579817,-0.01273071,0.11276037,0.04318843,-0.04068442,-0.00954273,-0.02578842,0.01790163,-0.04262736,-0.09824208,0.03434721,0.05006054,0.03632637,0.02450834,0.00458743,-0.01537398,0.01010791,0.1105189,-0.00386793,-0.03226193,0.01463366,0.00594428,-0.00322693,-0.0329096,0.03466621,-0.00543856,-0.02214094,0.05353254,-0.01604102,-0.02167724,0.0691595,0.01503438,0.03123179,-0.00810784,-0.00949483,-0.01929496,0.03442124,0.00897769,-0.04091685,0.08384777,0.04056982,0.01239684,0.13534854,0.03939324,0.03792426,0.02594077,0.05760356,-0.06130102,-0.04771008,-0.03330909,0.03511482,0.00224865,-0.02317125,-0.02226994,-0.05127553,0.05498509,0.04950508,0.12378373,-0.016061,-0.03761737,-0.08641473,-0.00136335,-0.01128691,0.07797669,0.01274757,-0.12406266,0.04665688,